const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// ---------------------
// Security middleware
// ---------------------

// Set secure HTTP headers (XSS protection, noSniff, frameguard, etc.)
app.use(helmet());

// CORS — restrict to known origins in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS
    ? process.env.ALLOWED_ORIGINS.split(',')
    : '*',
}));

// Rate limiting — prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Body parsing with size limits to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable x-powered-by to avoid leaking framework info
app.disable('x-powered-by');

// ---------------------
// Routes
// ---------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameters
    const { limit, offset } = req.query;

    if (limit !== undefined && (isNaN(Number(limit)) || Number(limit) < 1)) {
      return res.status(400).json({ error: 'Invalid "limit" parameter. Must be a positive integer.' });
    }
    if (offset !== undefined && (isNaN(Number(offset)) || Number(offset) < 0)) {
      return res.status(400).json({ error: 'Invalid "offset" parameter. Must be a non-negative integer.' });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const start = offset ? Number(offset) : 0;
    const end = limit ? start + Number(limit) : users.length;

    res.json(users.slice(start, end));
  } catch (err) {
    next(err);
  }
});

// ---------------------
// 404 handler
// ---------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ---------------------
// Global error handler
// ---------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// ---------------------
// Server start
// ---------------------
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

