const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Set secure HTTP headers (X-Content-Type-Options, Strict-Transport-Security, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a strict size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Global rate limiter — 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable the X-Powered-By header (also handled by helmet, but explicit is clear)
app.disable('x-powered-by');

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // --- Input validation for optional query parameters ---
  const { id, name } = req.query;

  if (id !== undefined) {
    const parsedId = Number(id);
    if (!Number.isInteger(parsedId) || parsedId <= 0) {
      return res.status(400).json({ error: 'Parameter "id" must be a positive integer.' });
    }
  }

  if (name !== undefined) {
    if (typeof name !== 'string' || name.length === 0 || name.length > 100) {
      return res.status(400).json({ error: 'Parameter "name" must be a non-empty string (max 100 chars).' });
    }
    // Allow only alphanumeric characters and spaces to prevent injection
    if (!/^[a-zA-Z0-9 ]+$/.test(name)) {
      return res.status(400).json({ error: 'Parameter "name" contains invalid characters.' });
    }
  }

  let users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Apply filters if provided
  if (id !== undefined) {
    users = users.filter((u) => u.id === Number(id));
  }
  if (name !== undefined) {
    const lowerName = name.toLowerCase();
    users = users.filter((u) => u.name.toLowerCase().includes(lowerName));
  }

  res.json(users);
});

// ---------------------------------------------------------------------------
// 404 handler — catch requests to undefined routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// ---------------------------------------------------------------------------
// Global error handler — MUST have 4 parameters for Express to recognise it
// ---------------------------------------------------------------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error internally; never expose it to the client
  console.error('Unhandled error:', err);

  const statusCode = err.statusCode || 500;
  const message =
    process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message || 'Internal server error.';

  res.status(statusCode).json({ error: message });
});

// ---------------------------------------------------------------------------
// Start server
// ---------------------------------------------------------------------------
const PORT = parseInt(process.env.PORT, 10) || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

