const express = require('express');
const helmet = require('helmet');        // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();

// --- Security middleware ---
app.use(helmet());                       // Sets secure HTTP headers
app.use(express.json({ limit: '10kb' })); // Body parser with size limit to prevent large payload attacks
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by'); // helmet does this too, but belt-and-suspenders

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Reject unexpected query parameters
  const allowedParams = ['id', 'name'];
  const unknownParams = Object.keys(req.query).filter(k => !allowedParams.includes(k));
  if (unknownParams.length > 0) {
    return res.status(400).json({ error: 'Unknown query parameters', params: unknownParams });
  }

  // Example: validate 'id' if provided
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
    }
  }

  // Example: validate 'name' if provided (alphanumeric + spaces only)
  if (req.query.name !== undefined) {
    if (typeof req.query.name !== 'string' || !/^[a-zA-Z\s]{1,100}$/.test(req.query.name)) {
      return res.status(400).json({ error: 'Invalid name parameter.' });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Filter sensitive fields — don't expose emails without auth
  const safeUsers = users.map(({ id, name }) => ({ id, name }));
  res.json(safeUsers);
});

// --- 404 handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (must have 4 params) ---
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message); // Log internally
  res.status(500).json({ error: 'Internal server error' }); // Never leak stack traces
});

// --- Startup with error handling ---
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

server.on('error', (err) => {
  if (err.code === 'EADDRINUSE') {
    console.error(`Port ${PORT} is already in use`);
  } else {
    console.error('Server startup error:', err.message);
  }
  process.exit(1);
});

module.exports = app;
```

